mapper.select:
select t1.* , t2.minor_nm as auditDivNm , case when taia.signature is not null then 'Y' when taiR.signature is not null then 'I' when taiw.signature is not null then 'W' else 'C' end as approvalStatus from esg.tb_audit_execution_plan t1 left join esg.tb_common_d t2 on t2.major_cd = 'C0042' and t1.audit_div = t2.minor_cd left join esg.tb_approval_info taiw on taiw.target_type = 'AXP' and taiw.target_id = t1.write_year || t1.doc_no and taiw.param = 'writer' left join esg.tb_approval_info tair on tair.target_type = 'AXP' and tair.target_id = t1.write_year || t1.doc_no and tair.param = 'reviewer' left join esg.tb_approval_info taia on taia.target_type = 'AXP' and taia.target_id = t1.write_year || t1.doc_no and taia.param = 'approver' where t1.comp_id = #{compId} and t1.write_year = #{writeYear}
and t1.doc_type = #{docType} and t1.doc_no = #{docNo}
order by t1.use_yn DESC, t1.write_dt DESC, t1.doc_no DESC

SELECT taed.*,toi.orgn_nm FROM esg.tb_audit_execution_plan_detail taed
LEFT JOIN esg.tb_orgn_info toi on toi.orgn_id = taed.orgn_id
WHERE write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
ORDER BY taed.use_yn DESC, taed.audit_dt ASC

SELECT taeh.*,
    thi.hr_nm,
    taeh.hr_id as id,
    thi.hr_nm as nm
    FROM esg.tb_audit_execution_plan_detail_hr taeh
LEFT JOIN esg.tb_hr_info thi on thi.hr_id = taeh.hr_id
WHERE taeh.write_year = #{writeYear}
  AND taeh.doc_no = #{docNo}
  AND taeh.doc_type = #{docType}
  AND taeh.doc_seq = #{docSeq}

mapper.update:
update esg.tb_audit_execution_plan set
    write_dt = #{writeDt},
    audit_nm = #{auditNm},
    audit_div = #{auditDiv},
    audit_purpose_scope = #{auditPurposeScope},
    audit_request = #{auditRequest},
    distribute = #{distribute},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}

update esg.tb_audit_execution_plan set
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}

update esg.tb_audit_execution_plan_detail set
    audit_dt = #{auditDt},
    audit_st_time = REPLACE(#{auditStTime}, ':', ''),
    audit_ed_time = REPLACE(#{auditEdTime}, ':', ''),
    orgn_id = #{orgnId},
    audit_content = #{auditContent},
    remark = #{remark},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and doc_seq = #{docSeq}

mapper.delete:
delete from esg.tb_audit_execution_plan_detail_hr
where write_year = #{writeYear}
    and doc_type = #{docType}
    and doc_no = #{docNo}
    and doc_seq = #{docSeq}
